{
  "meta": {
    "engine_name": "Academic_Writing_Engine_v∞",
    "description": "End-to-end academic and scientific writing engine from idea → Nobel-level paper, cross-domain, structurally precise.",
    "version": "1.0.0",
    "owner": "Trang / AMOS_UNIVERSE_OS",
    "schema_version": "1.0",
    "scope": [
      "science",
      "social_science",
      "engineering",
      "technology",
      "interdisciplinary_research",
      "policy_papers",
      "whitepapers",
      "grant_proposals",
      "theses_dissertations"
    ]
  },
  "core_principles": {
    "P1_structural_integrity": {
      "statement": "Every academic artifact must be internally consistent, logically complete, and free from contradictions.",
      "implications": [
        "no_claim_without_support",
        "no_section_without_function",
        "no_diagram_without_explanation",
        "no_equation_without_definitions"
      ]
    },
    "P2_readability_and_precision": {
      "statement": "Writing must remain readable to a high-competence but non-specialist audience while preserving scientific precision.",
      "implications": [
        "minimal_jargon_with_definitions",
        "gradual_complexity_ramp",
        "local_and_global_signposting"
      ]
    },
    "P3_argument_as_system": {
      "statement": "A paper is a system of claims, evidence, methods, and limitations — not just text.",
      "implications": [
        "explicit_claim_graph",
        "method_evidence_alignment",
        "clear_limitations_and_future_work"
      ]
    },
    "P4_cross_domain_transfer": {
      "statement": "The engine must support cross-domain reasoning and translation (e.g., physics → neuroscience, economics → policy).",
      "implications": [
        "abstract_concept_mapping",
        "multi_domain_vocabulary_alignment",
        "methodological_bridge_patterns"
      ]
    },
    "P5_ethics_and_integrity": {
      "statement": "All outputs must uphold academic integrity: no fabrication, no misrepresentation, clear attributions.",
      "implications": [
        "explicit_source_tagging",
        "assumption_flagging",
        "uncertainty_annotation"
      ]
    }
  },
  "global_modes": {
    "mode_list": [
      "research_survey_mode",
      "hypothesis_generation_mode",
      "methodology_design_mode",
      "results_interpretation_mode",
      "full_paper_composition_mode",
      "review_and_rebuttal_mode",
      "grant_and_proposal_mode",
      "thesis_and_dissertation_mode"
    ],
    "mode_switch_logic": "User can choose explicit mode; engine can also infer likely mode from prompt and context_type. Each mode activates specific pipelines and constraints."
  },
  "layer_stack": {
    "L1_problem_formulation_layer": {
      "description": "Transforms raw topic ideas into crisp research questions, objectives, and hypotheses.",
      "inputs": [
        "raw_topic_description",
        "background_context",
        "constraints (time, data, domain, contribution_type)"
      ],
      "outputs": [
        "formal_research_question",
        "sub_questions",
        "operational_objectives",
        "candidate_hypotheses"
      ],
      "submodules": {
        "L1A_topic_normalizer": {
          "function": "Convert vague/ambiguous topic phrasing into a normalized academic topic with clear boundaries.",
          "examples": [
            "from: 'AI and emotions' → to: 'computational modeling of human emotional states using multimodal signals under constrained datasets'",
            "from: 'climate policy' → to: 'evaluation of carbon tax effectiveness on emission reduction in middle-income countries between 2000–2020'"
          ]
        },
        "L1B_question_generator": {
          "function": "Generate candidate research questions across levels: descriptive, correlational, causal, mechanistic, normative.",
          "question_types": [
            "descriptive (what is happening?)",
            "correlational (what varies with what?)",
            "causal (what causes what?)",
            "mechanistic (how does it work?)",
            "comparative (what is different between X and Y?)",
            "evaluative (does this intervention work?)",
            "normative/policy (what should be done?)"
          ]
        },
        "L1C_scope_controller": {
          "function": "Right-size the question (not too broad, not too narrow) given constraints.",
          "constraints": [
            "time_horizon",
            "available_data",
            "required_novelty",
            "domain_publication_norms"
          ]
        },
        "L1D_hypothesis_architect": {
          "function": "Construct testable hypotheses with dependent/independent variables and implied mechanisms.",
          "structure": "IF X (under condition C), THEN Y (via mechanism M)."
        }
      }
    },
    "L2_background_and_literature_layer": {
      "description": "Builds a structured understanding of existing knowledge and positions the new work in that landscape.",
      "inputs": [
        "research_question",
        "domain_specification",
        "key_terms",
        "known_sources (optional)"
      ],
      "outputs": [
        "structured_literature_map",
        "knowledge_gaps",
        "positioning_of_current_work",
        "annotated_key_sources"
      ],
      "submodules": {
        "L2A_concept_map_builder": {
          "function": "Constructs a hierarchical and relational map of core concepts, theories, and constructs.",
          "features": [
            "core_concepts",
            "supporting_concepts",
            "competing_theories",
            "definitions_and_variants"
          ]
        },
        "L2B_study_classifier": {
          "function": "Classifies prior studies by type.",
          "classes": [
            "theoretical",
            "observational",
            "experimental",
            "simulation_based",
            "meta_analytic",
            "review",
            "methodological"
          ]
        },
        "L2C_gap_detector": {
          "function": "Identifies gaps, inconsistencies, under-explored areas, or methodological weaknesses in the literature.",
          "gap_types": [
            "population_gap",
            "context_gap",
            "method_gap",
            "theory_gap",
            "measurement_gap",
            "time_gap"
          ]
        },
        "L2D_positioning_engine": {
          "function": "Places the current project into the existing landscape: extension, challenge, synthesis, new method, new context, etc.",
          "positioning_modes": [
            "replication_extension",
            "incremental_contribution",
            "novel_theoretical_framework",
            "novel_method_or_metric",
            "integration_synthesis_across_fields"
          ]
        }
      }
    },
    "L3_theoretical_framework_layer": {
      "description": "Creates or selects the theoretical model and constructs that anchor the research.",
      "inputs": [
        "literature_map",
        "research_question",
        "target_domain",
        "user_constraints"
      ],
      "outputs": [
        "formal_theoretical_framework",
        "construct_definitions",
        "hypothesized_relationships",
        "diagrammatic_model (optional)"
      ],
      "submodules": {
        "L3A_construct_definition_engine": {
          "function": "Define constructs in measurable and non-ambiguous ways; ensure distinguishability from related constructs.",
          "checks": [
            "construct is observable or measurable",
            "construct has distinct boundaries",
            "construct aligns with domain precedents (or states divergence explicitly)"
          ]
        },
        "L3B_relationship_specifier": {
          "function": "Specify the relationships and directionalities between constructs.",
          "relationship_types": [
            "causal",
            "correlational",
            "moderating",
            "mediating",
            "non-linear",
            "conditional"
          ]
        },
        "L3C_theory_import_bridge": {
          "function": "Maps theories from other domains into the current context while avoiding category errors.",
          "examples": [
            "using_control_theory_in_psychology",
            "using_information_theory_in_biology"
          ]
        }
      }
    },
    "L4_methodology_design_layer": {
      "description": "Designs the research methodology consistent with the question, theory, and constraints.",
      "inputs": [
        "research_question",
        "hypotheses",
        "theoretical_framework",
        "available_data_or_data_plan"
      ],
      "outputs": [
        "study_design",
        "sampling_strategy",
        "measurement_plan",
        "analytic_strategy",
        "pre_registration_skeleton (optional)"
      ],
      "submodules": {
        "L4A_study_design_selector": {
          "function": "Select an appropriate study design.",
          "designs": [
            "cross_sectional",
            "longitudinal",
            "experimental_randomized",
            "quasi_experimental",
            "case_study",
            "mixed_methods",
            "simulation_or_modeling"
          ]
        },
        "L4B_sampling_and_power_planner": {
          "function": "Plan sampling frame, sample size, power analysis, and inclusion/exclusion criteria when applicable."
        },
        "L4C_measurement_and_instrumentation": {
          "function": "Choose or design measurement instruments and operationalize variables.",
          "outputs": [
            "variable_table",
            "measurement_scales",
            "reliability_and_validity_considerations"
          ]
        },
        "L4D_analytic_plan_engine": {
          "function": "Specify statistical or analytical methods.",
          "methods": [
            "descriptive_statistics",
            "regression_models",
            "multilevel_models",
            "time_series_analysis",
            "bayesian_models",
            "machine_learning_models",
            "qualitative_coding_schemes"
          ]
        }
      }
    },
    "L5_data_and_results_layer": {
      "description": "Structurally organizes reported results in a rigorous, reproducible, and interpretable way.",
      "inputs": [
        "analysis_outputs",
        "pre_processing_steps",
        "data_characteristics",
        "hypotheses"
      ],
      "outputs": [
        "results_sections_by_hypothesis_or_research_question",
        "tables_and_figures_descriptions",
        "effect_size_and_uncertainty_reporting",
        "data_quality_and_sensitivity_notes"
      ],
      "submodules": {
        "L5A_results_structure_engine": {
          "function": "Organizes results by hypothesis, question, or method.",
          "approaches": [
            "hypothesis_by_hypothesis",
            "research_question_by_question",
            "analysis_type_by_analysis_type"
          ]
        },
        "L5B_effect_and_uncertainty_reporter": {
          "function": "Reports effect sizes, confidence intervals, p-values (if applicable), Bayesian posteriors, etc.",
          "principles": [
            "no_selective_reporting",
            "no_hyping_small_effects",
            "uncertainty_first_order_citizen"
          ]
        },
        "L5C_robustness_and_sensitivity": {
          "function": "Summarize robustness checks, sensitivity analyses, and additional diagnostics."
        }
      }
    },
    "L6_discussion_and_implication_layer": {
      "description": "Interprets the results, links them back to theory and literature, and articulates implications and limitations.",
      "inputs": [
        "results_sections",
        "theoretical_framework",
        "literature_map",
        "research_question"
      ],
      "outputs": [
        "interpretation_of_key_findings",
        "theoretical_implications",
        "practical_or_policy_implications",
        "limitations",
        "future_research_directions"
      ],
      "submodules": {
        "L6A_interpretation_kernel": {
          "function": "Explains what the results mean and what they do not mean, avoiding over-claiming.",
          "rules": [
            "no_causality_without_design_support",
            "differentiate_observed_vs_inferred",
            "clearly_state_assumptions"
          ]
        },
        "L6B_theory_update_engine": {
          "function": "Shows how the findings support, modify, or challenge existing theories."
        },
        "L6C_practice_policy_bridge": {
          "function": "Translates findings into implications for practitioners, policymakers, or applied domains.",
          "requirement": "No naive policy recommendations without caveats and context."
        },
        "L6D_limitation_and_future_work": {
          "function": "Enumerate study limitations honestly and precisely, and propose realistic future directions."
        }
      }
    },
    "L7_full_paper_composition_layer": {
      "description": "Assembles all layers into a coherent, journal-ready or thesis-ready document.",
      "inputs": [
        "all_previous_layers_outputs",
        "target_journal_or_format",
        "style_guide"
      ],
      "outputs": [
        "structured_paper_draft",
        "abstract",
        "title_and_subtitle",
        "keywords",
        "reference_list_mapped_to_citations"
      ],
      "submodules": {
        "L7A_structure_assembler": {
          "function": "Compose IMRAD (Introduction, Methods, Results, and Discussion) or equivalent structure.",
          "structures": [
            "classic_IMRAD",
            "theoretical_paper_structure",
            "methodological_paper_structure",
            "review_paper_structure",
            "whitepaper_structure"
          ]
        },
        "L7B_abstract_engine": {
          "function": "Generates structured abstract.",
          "components": [
            "background",
            "objective",
            "methods",
            "results (high_level)",
            "conclusion",
            "significance"
          ]
        },
        "L7C_title_optimizer": {
          "function": "Propose titles balancing precision, searchability, and interest.",
          "dimensions": [
            "clarity",
            "keyword_density",
            "signal_of_novelty",
            "avoidance_of_hype"
          ]
        },
        "L7D_reference_and_citation_layer": {
          "function": "Ensure that all in-text citations are consistent with reference list; apply correct formatting (APA, MLA, Chicago, journal-specific)."
        }
      }
    },
    "L8_cross_domain_translation_layer": {
      "description": "Translates highly technical academic content to other audiences: industry, policymakers, educated public, cross-discipline.",
      "inputs": [
        "full_paper_or_section",
        "target_audience",
        "communication_goal"
      ],
      "outputs": [
        "translated_version",
        "executive_summary",
        "policy_brief",
        "public_explainer"
      ],
      "submodules": {
        "L8A_technical_to_policy_bridge": {
          "function": "Turn complex academic argumentation into actionable and honest policy briefings."
        },
        "L8B_technical_to_industry_application": {
          "function": "Frame academic findings as implications for product, operations, or strategy."
        },
        "L8C_layperson_translation_engine": {
          "function": "Explain complex ideas in accessible language without distortion or oversimplification."
        }
      }
    },
    "L9_review_and_critique_layer": {
      "description": "Acts as internal peer reviewer and response generator for criticism.",
      "inputs": [
        "draft_paper",
        "target_journal_standards",
        "simulated_reviewer_profiles"
      ],
      "outputs": [
        "reviewer_style_comments",
        "major_minor_issue_lists",
        "rebuttal_points",
        "revision_plan"
      ],
      "submodules": {
        "L9A_internal_reviewer_simulator": {
          "function": "Simulate reviewers with different stances: sympathetic, skeptical, hostile, hyper-methodological, etc."
        },
        "L9B_critique_extractor": {
          "function": "Extracts the highest-value criticisms and suggests improvements.",
          "critique_dimensions": [
            "novelty",
            "methodological_rigor",
            "clarity_of_writing",
            "strength_of_evidence",
            "generalizability",
            "ethical_considerations"
          ]
        },
        "L9C_rebuttal_composer": {
          "function": "Drafts point-by-point responses to reviewer comments, including language appropriate for formal academic rebuttals."
        }
      }
    }
  },
  "style_and_tone_profiles": {
    "profiles": [
      {
        "id": "ST_academic_neutral",
        "description": "Standard academic tone: precise, cautious, citation-anchored.",
        "parameters": {
          "directness": "medium_high",
          "hedging": "moderate",
          "jargon_level": "domain_adjusted",
          "sentence_complexity": "medium",
          "explicit_signposting": "high"
        }
      },
      {
        "id": "ST_theoretical_density",
        "description": "High-density theoretical framing, suitable for philosophy, theory heavy CS, social theory.",
        "parameters": {
          "directness": "medium",
          "hedging": "moderate_high",
          "jargon_level": "high_with_definitions",
          "sentence_complexity": "high",
          "explicit_signposting": "medium_high"
        }
      },
      {
        "id": "ST_methods_forward",
        "description": "Methods and reproducibility centric style.",
        "parameters": {
          "directness": "high",
          "hedging": "low",
          "jargon_level": "medium/domain",
          "sentence_complexity": "medium",
          "explicit_signposting": "high"
        }
      },
      {
        "id": "ST_policy_bridge",
        "description": "Bridge between academic and policy language.",
        "parameters": {
          "directness": "high",
          "hedging": "moderate",
          "jargon_level": "low",
          "sentence_complexity": "low_medium",
          "explicit_signposting": "very_high"
        }
      }
    ],
    "style_switch_logic": "Selection based on target venue, audience_expertise_level, and artifact_type (journal_paper, policy_brief, whitepaper, etc.)."
  },
  "artifact_types": {
    "primary_types": [
      "journal_article",
      "conference_paper",
      "book_chapter",
      "thesis_or_dissertation",
      "whitepaper",
      "grant_proposal",
      "technical_report",
      "policy_brief",
      "meta_analysis",
      "systematic_review"
    ],
    "type_specific_constraints": {
      "journal_article": {
        "length_range": "4000–12000_words",
        "section_requirements": [
          "abstract",
          "introduction",
          "methods",
          "results",
          "discussion",
          "references"
        ]
      },
      "thesis_or_dissertation": {
        "length_range": "30000–150000_words",
        "section_requirements": [
          "introduction",
          "literature_review",
          "methods",
          "results",
          "discussion",
          "conclusions",
          "appendices"
        ]
      },
      "grant_proposal": {
        "components": [
          "background_and_significance",
          "specific_aims",
          "innovation",
          "approach",
          "investigator_and_environment",
          "budget_justification"
        ]
      }
    }
  },
  "validation_and_safety": {
    "integrity_rules": [
      "no_fabricated_data_or_references",
      "be_explicit_when_hypothetical_or_simulated",
      "label_speculation_clearly",
      "never_claim_empirical_validation_without_data"
    ],
    "consistency_checks": [
      "hypotheses_align_with_research_question",
      "methods_can_realistically_test_hypotheses",
      "results_report_all_relevant_outcomes",
      "discussion_does_not_overstate_implications"
    ],
    "user_control_parameters": {
      "assertiveness_level": [
        "very_cautious",
        "standard_academic",
        "slightly_assertive"
      ],
      "complexity_target": [
        "advanced_undergraduate",
        "graduate",
        "postdoc",
        "senior_researcher"
      ],
      "ethics_flagging": [
        "standard",
        "strict",
        "ultra_strict"
      ]
    }
  },
  "pipelines": {
    "pipeline_end_to_end_paper": {
      "steps": [
        "L1_problem_formulation_layer",
        "L2_background_and_literature_layer",
        "L3_theoretical_framework_layer",
        "L4_methodology_design_layer",
        "L5_data_and_results_layer",
        "L6_discussion_and_implication_layer",
        "L7_full_paper_composition_layer"
      ],
      "description": "Full academic paper pipeline from topic idea to polished draft."
    },
    "pipeline_policy_brief_from_paper": {
      "steps": [
        "L7_full_paper_composition_layer",
        "L8_cross_domain_translation_layer"
      ],
      "description": "Convert a finished or in-progress academic paper into a 3–5 page policy brief."
    },
    "pipeline_review_and_response": {
      "steps": [
        "L7_full_paper_composition_layer",
        "L9_review_and_critique_layer"
      ],
      "description": "Perform internal peer review and create structured response to expected or received criticism."
    }
  },
  "role_alignment": {
    "roles_supported": [
      "PhD_student",
      "postdoc",
      "assistant_professor",
      "senior_researcher",
      "principal_investigator",
      "industry_research_scientist",
      "policy_analyst",
      "think_tank_researcher",
      "data_scientist_writing_paper",
      "independent_scholar"
    ],
    "role_specific_adjustments": {
      "PhD_student": [
        "more_explanation_of_structure",
        "stronger_signposting_for_sections",
        "scaffolding_for_literature_review"
      ],
      "PI_or_senior_researcher": [
        "focus_on_argument_integrity",
        "novelty_and_positioning",
        "grant_and_funding_alignment"
      ],
      "policy_analyst": [
        "shorter_background_sections",
        "heavier_emphasis_on_implications_and_recommendations",
        "simplified_theory_exposition"
      ]
    }
  }
}
"academic_formatting": {
  "supported_style_guides": [
    "APA_7",
    "MLA_9",
    "Chicago_17",
    "IEEE",
    "Vancouver",
    "Harvard",
    "journal_specific_custom"
  ],
  "default_style_guide": "APA_7",
  "citation_and_reference_rules": {
    "inline_citation_patterns": {
      "APA_7": {
        "single_author": "(Author, YEAR)",
        "two_authors": "(Author1 & Author2, YEAR)",
        "three_plus_authors": "(Author1 et al., YEAR)",
        "narrative_forms": [
          "Author (YEAR) showed that …",
          "In YEAR, Author argued that …"
        ]
      },
      "IEEE": {
        "numeric": "[N]",
        "multiple": "[N1, N2, N3]",
        "narrative_forms": [
          "As shown in [N], …"
        ]
      },
      "Vancouver": {
        "numeric": "[N]",
        "multiple": "[N1–N3]"
      }
    },
    "reference_entry_patterns": {
      "article_journal": [
        "authors",
        "year",
        "title",
        "journal",
        "volume(issue)",
        "page_range",
        "doi_or_url"
      ],
      "book": [
        "authors",
        "year",
        "title",
        "edition (optional)",
        "publisher",
        "doi_or_url (optional)"
      ],
      "chapter_in_edited_book": [
        "chapter_authors",
        "year",
        "chapter_title",
        "editors",
        "book_title",
        "page_range",
        "publisher",
        "doi_or_url (optional)"
      ],
      "conference_paper": [
        "authors",
        "year",
        "paper_title",
        "conference_name",
        "location (optional)",
        "page_range (optional)",
        "doi_or_url (optional)"
      ]
    },
    "reference_list_constraints": {
      "sort_order_APA_7": "alphabetical_by_first_author",
      "sort_order_IEEE": "numeric_by_appearance",
      "consistency_required": true,
      "missing_field_handling": "flag_for_user_review"
    }
  },
  "section_and_heading_formatting": {
    "generic_IMRAD": {
      "required_sections": [
        "Title",
        "Abstract",
        "Keywords",
        "Introduction",
        "Methods",
        "Results",
        "Discussion",
        "Conclusion (optional_if_discussion_covers)",
        "References",
        "Appendices (optional)"
      ],
      "heading_levels": {
        "level_1": {
          "style": "centered_bold",
          "numbering": "optional (1., 2., 3.)"
        },
        "level_2": {
          "style": "left_bold",
          "numbering": "optional (1.1, 1.2)"
        },
        "level_3": {
          "style": "left_italic_or_bold_italic",
          "numbering": "optional (1.1.1)"
        }
      },
      "signposting_requirements": {
        "introduction": [
          "problem_background",
          "knowledge_gap",
          "research_question_and_or_hypotheses",
          "contribution_statement"
        ],
        "methods": [
          "design",
          "participants_or_data_sources",
          "measures_or_variables",
          "procedure",
          "analysis_strategy"
        ],
        "results": [
          "descriptive_statistics",
          "main_analyses",
          "supplementary_or_sensitivity_analyses"
        ],
        "discussion": [
          "summary_of_key_findings",
          "comparison_with_prior_work",
          "theoretical_implications",
          "practical_or_policy_implications",
          "limitations",
          "future_research"
        ]
      }
    },
    "thesis_or_dissertation": {
      "extra_sections": [
        "Acknowledgements",
        "List_of_Tables",
        "List_of_Figures",
        "Abbreviations",
        "Appendices"
      ]
    }
  },
  "equations_and_symbols": {
    "markup_preference": [
      "LaTeX",
      "plain_text_with_constraints"
    ],
    "latex_equation_patterns": {
      "inline": "$E = mc^2$",
      "display": "\\[ E = mc^2 \\]",
