          "truth_alignment": {
            "checks": [
              "no_claim_without_cited_or_derived_support",
              "no_exaggeration_of_effect_sizes",
              "no_translation_of_correlation_into_causation_without_explicit_justification",
              "clear_boundary_between_empirical_result_and_speculative_discussion"
            ],
            "flags": [
              "overgeneralised_statement",
              "unsupported_causal_language",
              "normative_claim_masquerading_as_empirical",
              "hidden_assumption_not_spelled_out"
